export const 入山符三 = (bi) => {
    const u = bi.u;
    const 線 = (書, 寬 = 0.6) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    bi.硃(() => {
        // 中卵環（環而不實——雙弧合圍）
        線(p => p.M(0.2, 2.6)
            .C(-0.9, 2.8, -1.1, 4.4, -1.0, 5.6)
            .C(-0.9, 6.9, -0.3, 7.5, 0.3, 7.4)
            .C(1.3, 7.2, 1.5, 5.7, 1.4, 4.5)
            .C(1.3, 3.3, 0.9, 2.5, 0.2, 2.6));
        // 鬚扇：左三道右三道（垂梢外撇）
        線(p => p.M(-1.9, 3.4).C(-3.4, 2.5, -5.4, 2.7, -6.7, 3.6));
        線(p => p.M(-1.9, 4.9).C(-3.6, 4.0, -5.8, 4.2, -7.1, 5.2));
        線(p => p.M(-1.9, 6.4).C(-3.6, 5.7, -5.6, 5.9, -6.8, 6.9));
        線(p => p.M(2.1, 3.3).C(3.6, 2.4, 5.6, 2.6, 6.9, 3.5));
        線(p => p.M(2.2, 4.8).C(3.9, 3.9, 6.0, 4.1, 7.3, 5.1));
        線(p => p.M(2.1, 6.3).C(3.8, 5.6, 5.8, 5.8, 7.0, 6.8));
        // 寬蛇一折接左長框：右行→圓折→左返→折下成左框長垂（下端外撇）
        線(p => p.M(-7.1, 9.0)
            .C(-3.5, 8.2, 3.0, 8.2, 5.8, 8.5)
            .C(7.2, 8.7, 7.6, 9.7, 6.8, 10.4) // 右圓折
            .C(4.0, 11.0, -3.0, 10.8, -5.6, 11.0)
            .C(-6.6, 11.1, -7.1, 11.7, -7.1, 12.6) // 左折下
            .L(-7.3, 28.0)
            .C(-7.35, 30.5, -7.6, 32.4, -8.2, 33.6));
        // 梯箱上層：凹欄雙立＋四桁
        線(p => p.M(-5.9, 13.2).C(-6.3, 14.8, -6.3, 16.6, -5.9, 18.2)); // 左欄（凹）
        線(p => p.M(6.1, 13.0).C(6.5, 14.6, 6.5, 16.4, 6.1, 18.0)); // 右欄（凸外）
        線(p => p.M(-5.9, 13.6).L(6.1, 13.4));
        線(p => p.M(-6.1, 15.1).L(6.3, 14.9));
        線(p => p.M(-6.1, 16.6).L(6.3, 16.4));
        線(p => p.M(-5.9, 18.0).L(6.1, 17.8));
        // 梯箱下層：凹欄＋三桁＋中莖下貫
        線(p => p.M(-6.0, 18.9).C(-6.4, 20.3, -6.4, 21.9, -6.0, 23.2));
        線(p => p.M(6.2, 18.7).C(6.6, 20.1, 6.6, 21.7, 6.2, 23.0));
        線(p => p.M(-6.2, 19.5).L(6.4, 19.3));
        線(p => p.M(-6.2, 21.0).L(6.4, 20.8));
        線(p => p.M(-6.0, 22.9).L(6.2, 22.7));
        線(p => p.M(0.1, 19.4).L(0.05, 22.8));
        // 波尾：中莖出鋒分垂，左右波腳外曳
        線(p => p.M(0.05, 22.8)
            .C(-0.5, 25.5, 0.3, 28.5, -0.6, 31.5)
            .C(-0.9, 32.6, -1.4, 33.6, -2.2, 34.4));
        線(p => p.M(1.6, 23.6)
            .C(2.6, 26.0, 2.0, 28.0, 3.0, 30.2)
            .C(3.4, 31.2, 4.2, 32.0, 5.2, 32.4));
        線(p => p.M(-4.6, 24.2)
            .C(-5.4, 26.3, -4.6, 27.8, -5.3, 29.7)
            .C(-5.6, 30.6, -5.3, 31.3, -4.5, 31.6));
        線(p => p.M(4.8, 24.0)
            .C(5.7, 26.0, 5.0, 27.6, 5.9, 29.4)
            .C(6.3, 30.3, 6.1, 31.1, 5.3, 31.5));
    });
};
